    mint_bump: u8, feature_id_bump: u8,
) -> ProgramResult {
    let mint_address = Pubkey::create_program_address(
        &[&feature_proposal_info.key.to_bytes(), br"mint", &[mint_bump]],
        program_id,
    )?;
    if mint_address != *mint_info.key {
        return Err(ProgramError::InvalidArgument);
